use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type VaultDatum {
  owner: ByteArray,
  min_tokens: Int,
}

validator parametric_vault(policy_id: ByteArray) {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let owner_signed = list.has(self.extra_signatories, d.owner)
    let has_enough_tokens =
      list.any(
        self.outputs,
        fn(output) {
          let tokens = assets.tokens(output.value, policy_id)
          list.any(
            assets.tokens(output.value, policy_id)
              |> fn(t) {
                  use aiken/collection/dict
                  dict.keys(t)
                },
            fn(asset_name) {
              assets.quantity_of(output.value, policy_id, asset_name) >= d.min_tokens
            },
          )
        },
      )
    owner_signed && has_enough_tokens
  }

  else(_) {
    fail
  }
}
